def parse_range(header: str):
    if not header.startswith('bytes='):
        return None
    spec = header[len('bytes='):]
    if '-' not in spec:
        return None
    a, _, b = spec.partition('-')
    if not a.isdigit() or not b.isdigit():
        return None
    return int(a), int(b)

